## Creating a Class Relation using Matrix Notation
As of February 2026, we can create a class relation using matrix notation to represent a relation and include member functions to check if the relation is reflexive, symmetric, anti-symmetric, and transitive.

### Code Implementation
```python
class Relation:
    def __init__(self, matrix):
        self.matrix = matrix
        self.n = len(matrix)

    def is_reflexive(self):
        for i in range(self.n):
            if self.matrix[i][i] == 0:
                return False
        return True

    def is_symmetric(self):
        for i in range(self.n):
            for j in range(self.n):
                if self.matrix[i][j] != self.matrix[j][i]:
                    return False
        return True

    def is_anti_symmetric(self):
        for i in range(self.n):
            for j in range(self.n):
                if i != j and self.matrix[i][j] == 1 and self.matrix[j][i] == 1:
                    return False
        return True

    def is_transitive(self):
        for i in range(self.n):
            for j in range(self.n):
                for k in range(self.n):
                    if self.matrix[i][j] == 1 and self.matrix[j][k] == 1 and self.matrix[i][k] == 0:
                        return False
        return True

    def is_equivalence(self):
        return self.is_reflexive() and self.is_symmetric() and self.is_transitive()

    def is_partial_order(self):
        return self.is_anti_symmetric() and self.is_transitive() and self.is_reflexive()

# Example usage
matrix = [[1, 0, 0], [0, 1, 0], [0, 0, 1]]
relation = Relation(matrix)
print("Is reflexive:", relation.is_reflexive())
print("Is symmetric:", relation.is_symmetric())
print("Is anti-symmetric:", relation.is_anti_symmetric())
print("Is transitive:", relation.is_transitive())
