    cout << "Is equivalence: " << (relation.isEquivalence() ? "Yes" : "No") << endl;
    cout << "Is partial order: " << (relation.isPartialOrder() ? "Yes" : "No") << endl;

    // Deallocate memory
    for (int i = 0; i < n; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    return 0;
}
```

